import { describe, expect, it } from 'vitest';
import { buildGuardianSummary } from '../../src/tutor/disclosure_summary';

describe('buildGuardianSummary', () => {
  it('returns structured summary fields instead of transcript dumps', () => {
    const summary = buildGuardianSummary({
      sessionId: 'sess-1',
      lessonId: 'lesson-1',
      progress: 'completed-step-2',
      interventions: ['pause'],
      transcript: ['child said something sensitive']
    });
    expect(summary.transcript).toBeUndefined();
    expect(summary.progress).toBe('completed-step-2');
  });
});

